<?php
namespace App\Http\Controllers;use App\Models\Content;use App\Models\Enquiry;use App\Models\User;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Support\Facades\Artisan;
class AdminController extends Controller{public function analytics():JsonResponse{return response()->json(['content'=>Content::selectRaw('type,count(*) as total')->groupBy('type')->pluck('total','type'),'enquiries'=>['total'=>Enquiry::count(),'new'=>Enquiry::where('status','new')->count(),'this_month'=>Enquiry::whereMonth('created_at',now()->month)->count()],'recent'=>Enquiry::latest()->limit(8)->get()]);}public function enquiries():JsonResponse{return response()->json(Enquiry::latest()->paginate(25));}public function updateEnquiry(Request $r,Enquiry $enquiry):JsonResponse{$data=$r->validate(['status'=>['required','in:new,in_progress,resolved,spam']]);$enquiry->update($data);return response()->json($enquiry);}public function upload(Request $r):JsonResponse{$r->validate(['image'=>['required','image','max:5120']]);return response()->json(['path'=>$r->file('image')->store('content','public')],201);}public function users():JsonResponse{return response()->json(User::paginate(25));}public function storeUser(Request $r):JsonResponse{$data=$r->validate(['name'=>['required','string','max:120'],'email'=>['required','email','unique:users'],'password'=>['required','min:12'],'role'=>['required','in:admin,editor']]);return response()->json(User::create($data),201);}public function backup():JsonResponse{Artisan::call('backup:run');return response()->json(['message'=>'Backup completed.','output'=>Artisan::output()]);}}
